INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (1, 0, 1, 105, 0, 0.029, 101, 1, 1.5, 110, "仲間と夏を楽しむ、夏海の魔法士。自分を変えたいという固い決意で、障害物を無効化して走り続ける。", 122601, 1, 160);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (2, 0, 2, 111, 1, 0.014, 102, 3, 2.5, 105, "太陽よりも輝く、夏海の元気娘。　持ち前の身体能力で、どんなコースも柔軟に対応し、駆け抜ける。", 122401, 0, 120);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (3, 1, 3, 105, 0, 0.017, 103, 2, 2.5, 110, "波打ち際に煌めく、夏海の剣士。　日々の鍛錬で鍛えた脚で、長い距離も速度を落とさず走り切る。", 122501, 0, 350);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (4, 0, 4, 105, 1, 0.016, 104, 3, 1.5, 110, "海の幸に目がない、渚のお姫様。　『王家の装備』の力を解放し、障害物をものともせず前へと進む。", 107501, 0, 130);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (5, 0, 5, 105, 0, 0.014, 105, 1, 2.5, 110, "海でも主さまをお世話する、白浜の巫女。精霊の力で自身を加速させ、誰よりも速くゴールを目指す。", 107601, 1, 160);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (6, 1, 6, 103, 0, 0.029, 106, 2, 3.5, 120, "水着姿を恥じらう、ツンデレ猫娘。お得意の魔法で、対戦相手の走りを妨害し、レースを有利に進める。", 107801, 0, 255);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (7, 0, 7, 103, 0, 0.013, 107, 1, 3.5, 120, "優雅に浜を駆ける、真夏のマホ姫。しゃなりしゃなりと、雅な身のこなしで障害物を跳び越えていく。", 110601, 1, 160);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (8, 1, 8, 103, 0, 0.014, 108, 2, 2.5, 110, "浜の平和を守る、真夏の狼娘。　　獣人の強靭なスタミナで、レース　後半にスパートをかける。", 110401, 0, 350);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (9, 0, 9, 100, 1, 0.012, 109, 3, 1.5, 105, "浜に力強く舞う、真夏の南国娘。　レースの喧噪の中でも精神を乱さず後半に大きな捲りを見せる。", 110501, 0, 130);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (10, 0, 10, 103, 0, 0.014, 110, 1, 2.5, 105, "浜の事件を嗅ぎ付けた、真夏の　　名探偵。高い推理力と魔法で、的確に対戦相手の走りを乱す。", 115701, 1, 200);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (11, 1, 11, 103, 0, 0.071, 111, 2, 2.5, 105, "再び鎧を脱いだ、灼熱の騎士団長。実戦で培った判断力で、瞬時にバリアを展開し、障害物を無力化する。", 113601, 0, 350);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (12, 0, 12, 103, 1, 0.014, 112, 3, 1.5, 120, "水が苦手な、海辺の気まぐれ猫娘。浜に現れた美少女義賊は、対戦相手のスピードを奪いとる。", 107901, 0, 130);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (13, 0, 13, 105, 0, 0.022, 113, 2, 1.5, 110, "バカンスも効率第一な、海の傭兵。レースでも最高効率を求め、どんな状況でも隙のない走りを見せる。", 108001, 1, 200);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (14, 0, 14, 108, 0, 0.031, 114, 1, 2.5, 110, "真夏の太陽が良く似合う、海辺の　サレンママ。多才で器用、どんな　障害物もエレガントに越えていく。", 110301, 1, 160);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (15, 0, 15, 105, 1, 0.036, 115, 1, 0.5, 110, "海に嵐を呼ぶ夏のドジっ娘メイド。日頃から災難に慣れており、多少　のトラブルには動じたりしない。", 107701, 0, 130);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (16, 1, 16, 95, 0, 0.048, 116, 2, 3.5, 110, "粋な夏を愉しむ、若夏の姉御。　　流麗な身体捌きで、始・継・終と、UBを重ねるごとに、加速する。", 113101, 0, 350);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (17, 0, 17, 105, 1, 0.043, 117, 3, 1.5, 105, "夏のトキメキに触れた、オタク魔法少女。多彩な魔法を操り、少しずつ他の走者の速度を落とし続ける。", 113301, 0, 130);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (18, 0, 18, 95, 1, 0.018, 118, 2, 1.5, 105, "海獄に降臨せし、真夏の冥姫。　　レース後半に魔力を全解放し、　　蒼き疾風と成りて浜を駆け抜ける。", 113201, 0, 130);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (19, 0, 19, 108, 0, 0.021, 119, 2, 2.5, 110, "夏の夕を火花で彩る、渚の壊し屋。『壊し屋』の異名と過激な愛情は、対戦相手にプレッシャーを与える。", 117001, 1, 160);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (20, 1, 20, 105, 0, 0.036, 120, 1, 2.5, 110, "青春に生きる者を導く、夏の先生。夢へと邁進する聖母の加護が、その身をあらゆる困難から守る。", 113501, 0, 255);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (21, 1, 21, 105, 0, 0.02, 121, 3, 2.5, 105, "笑顔の応援が眩しい、夏の超能力　ガール。超能力を駆使して、どんな障害物もひとっ飛びで乗り越える。", 113401, 0, 350);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (22, 0, 22, 105, 1, 0.018, 122, 1, 2.5, 110, "海辺で大人の魅力を放つ、夏の　　セクシー先生。その魅力に囚われた対戦相手は、走りを乱してしまう。", 110101, 0, 130);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (23, 0, 23, 111, 0, 0.03, 123, 3, 3.5, 105, "水着も絶対外さない、夏のカリスマモデル。走りのバイブスは超テンアゲで、スピードはおにやば。", 110001, 1, 160);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (24, 0, 24, 103, 1, 0.027, 124, 1, 1.5, 110, "南の島も盛り上げる、真夏のアイドル。悪天候でも笑顔を絶やさず後半もリズムを上げて走り切る。", 117201, 0, 130);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (25, 0, 25, 108, 0, 0.02, 125, 2, 3.5, 105, "海原に美声を響かす、渚の歌姫。　守護の賛歌と精霊の加護により、　障害物から身を守る。", 117301, 1, 160);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (26, 1, 26, 105, 0, 0.04, 126, 3, 2.5, 110, "夏でも天邪鬼な、夕凪のテーラー。張り巡らされた魔法の糸で、他の走者の自由を奪う。", 117401, 0, 350);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (27, 1, 27, 105, 0, 0.009, 127, 1, 3.5, 110, "向日葵が良く似合う、海辺の　　　お姉ちゃん。秘密結社の一員で、　抜群の身体能力が一番の武器。", 117101, 0, 350);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (28, 1, 28, 105, 0, 0.022, 128, 1, 3.5, 120, "渚でおっとり、夏色うさぎっこ。　うさぎさんパワー全開で、ぴょん　ぴょんとコースを跳ね回る。", 122901, 0, 255);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (29, 0, 29, 105, 1, 0.028, 129, 3, 2.5, 110, "無邪気さ弾ける、夏色いたずら娘。砂浜でも、いたずらの準備は万端！レースに大波乱が巻き起こる！？", 122801, 0, 130);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (30, 0, 30, 108, 0, 0.023, 130, 2, 3.5, 105, "海でも真面目な、夏色優等生。　　高めた魔力を解き放ち、一瞬の内に他の走者を置き去りにする。", 122701, 1, 130);
